export type RealmOperationKey = keyof typeof REALM_OPERATION_MAP;
export type RealmOperationMap = typeof REALM_OPERATION_MAP;
export type RealmServiceMethodMap = typeof REALM_SERVICE_METHODS;

type OperationId<K extends RealmOperationKey> = RealmOperationMap[K]['operationId'];
type OperationSchema<K extends RealmOperationKey> = OperationId<K> extends keyof operations
  ? operations[OperationId<K>]
  : never;
type ValueOf<T> = T[keyof T];
type ResolveNever<T, Fallback> = [T] extends [never] ? Fallback : T;
type OperationSuccessResponse<K extends RealmOperationKey> = OperationSchema<K> extends { responses: infer R }
  ? ResolveNever<
      {
        [Code in keyof R]: `${Code & (string | number)}` extends `2${string}` ? R[Code] : never;
      }[keyof R],
      'default' extends keyof R ? R['default'] : never
    >
  : never;
type OperationSuccessContent<K extends RealmOperationKey> = OperationSuccessResponse<K> extends { content?: infer C }
  ? NonNullable<C>
  : never;
export type RealmOperationResult<K extends RealmOperationKey> = ResolveNever<
  ValueOf<OperationSuccessContent<K>>,
  unknown
>;
export type RealmOperationResultMap = {
  [K in RealmOperationKey]: RealmOperationResult<K>;
};
